var doc = uiapp.ActiveUIDocument.Document;
var level = new FilteredElementCollector(doc).OfClass(typeof(Level)).Cast<Level>().FirstOrDefault();
var wallType = new FilteredElementCollector(doc).OfClass(typeof(WallType)).Cast<WallType>().FirstOrDefault();
if (level == null || wallType == null) return new { placed = false, reason = "no level or wall type available" };
var p1 = new XYZ(0, 0, 0);
var p2 = new XYZ(10, 0, 0);
var line = Line.CreateBound(p1, p2);
var wall = Wall.Create(doc, line, wallType.Id, level.Id, 10.0, 0.0, false, false);
return new { placed = true, id = wall.Id.Value, wall_type = wallType.Name };
